--
-- Table structure for table `Invoice`
--

DROP TABLE IF EXISTS `Invoice`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `Invoice` (
  `id` int NOT NULL AUTO_INCREMENT,
  `invoiceNo` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `customerId` int NOT NULL,
  `safeId` int NOT NULL,
  `branchId` int NOT NULL,
  `paymentMethod` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Nakit',
  `exchangeRate` double NOT NULL DEFAULT '1',
  `deliveryType` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Mağazadan Teslim',
  `shippingCompany` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `trackingNumber` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `totalAmountTl` double NOT NULL DEFAULT '0',
  `totalAmountUsd` double NOT NULL DEFAULT '0',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `type` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'SATIS',
